"use client";

import Link from "next/link";
import { useState } from "react";
import { Activity, ArrowRight, FileCheck2, Lightbulb, RotateCcw, ShieldCheck } from "lucide-react";
import type { CheckReport } from "@/lib/types";

export function ResultClient({ initialReport, reportId }: { initialReport: CheckReport | null; reportId: string }) {
  const [report, setReport] = useState<CheckReport | null>(initialReport);
  const [evidenceText, setEvidenceText] = useState(report?.bestFix.evidenceText ?? "");
  const [isRechecking, setIsRechecking] = useState(false);

  async function recheck() {
    if (!evidenceText.trim() || !report || isRechecking) return;
    setIsRechecking(true);
    const res = await fetch(`/api/report/${report.id}/evidence`, {
      method: "POST",
      headers: { "Content-Type": "application/json" },
      body: JSON.stringify({ evidenceText })
    });
    const updated = (await res.json()) as CheckReport;
    window.setTimeout(() => {
      setReport(updated);
      setIsRechecking(false);
    }, 700);
  }

  if (!report) {
    return (
      <main className="app-shell compact">
        <HeaderLite />
        <section className="panel empty-state">
          <h2>没有找到这份体检报告</h2>
          <p>回到首页重新做一次投前体检。</p>
          <Link className="primary-link" href="/" data-empty-cta="回到投前体检台">回到投前体检台</Link>
        </section>
      </main>
    );
  }

  const isGreen = report.trafficLight === "green";

  return (
    <main className="app-shell" data-visual-lane="operational-dashboard / blueprint-lab 混合。" data-hero-composition="result-workbench" data-testid="screen-result">
      <HeaderLite />
      <section className="result-grid">
        <aside className={`panel apply-light ${report.trafficLight}`} data-testid="traffic-light-result">
          <span className="status-pill blue">投递建议</span>
          <div className="light-core" />
          <h2>{report.trafficLightLabel}</h2>
          <p>{report.scoreReason}</p>
          <div className="score-block" data-testid="score-panel">
            <span>招聘官视角评分</span>
            <strong data-testid="score-number">{report.score}</strong>
            <small>分</small>
          </div>
          {report.scoreDelta ? <b className="delta-badge" data-testid="score-delta">+{report.scoreDelta}</b> : <span className="subtle">补证据后可提升到 78 分</span>}
        </aside>

        <section className="panel gaps-panel">
          <div className="panel-head clean">
            <div>
              <h2>{isGreen ? "关键证据已补齐" : "3 个证据缺口"}</h2>
              <p>每条缺口都绑定岗位要求和当前简历证据。</p>
            </div>
            <span className="status-pill violet">不是润色，是体检</span>
          </div>
          <div className="gap-stack" data-testid="evidence-gap-list">
            {report.gaps.map((gap) => (
              <article className={`gap-card ${gap.status}`} key={gap.id} data-testid="evidence-gap-item">
                <div className="gap-top">
                  <span className={`evidence-badge ${gap.status === "proven" ? "green" : gap.status === "weak" ? "yellow" : "red"}`}>{gap.status === "proven" ? "已有证据" : gap.status === "weak" ? "证据较弱" : "缺少证据"}</span>
                  <span>{gap.impact}</span>
                </div>
                <h3>{gap.title}</h3>
                <p>{gap.currentEvidence}</p>
                <details data-testid="evidence-gap-detail">
                  <summary>查看岗位依据和缺口</summary>
                  <p><b>岗位要求：</b>{gap.requirement}</p>
                  <p><b>仍需补充：</b>{gap.missingEvidence}</p>
                </details>
              </article>
            ))}
          </div>
        </section>

        <aside className="panel fix-panel" data-testid="best-fix-card">
          <span className="status-pill blue">现在最值得补的一件事</span>
          <h2>{isGreen ? "把证据写回简历项目经历" : report.bestFix.title}</h2>
          <p>{isGreen ? report.card.nextAction : report.bestFix.detail}</p>
          <div
            className="evidence-editor"
            contentEditable={true}
            suppressContentEditableWarning
            data-testid="evidence-input"
            role="textbox"
            aria-label="补充证明材料"
            onInput={(event) => setEvidenceText(event.currentTarget.textContent ?? "")}
          >
            {evidenceText}
          </div>
          <button className="secondary-button wide min-h-11 min-w-11" onClick={() => setEvidenceText(report.bestFix.evidenceText)} data-testid="use-evidence-button" type="button">
            <FileCheck2 size={18} />
            使用这条证明材料
          </button>
          <button className="primary-button wide min-h-11 min-w-11" onClick={recheck} disabled={isRechecking || isGreen} data-testid="recheck-button" data-next-step-cta="重新体检并刷新证据卡" type="button">
            <RotateCcw size={18} />
            {isRechecking ? "正在重新体检" : isGreen ? "证据卡已刷新" : "重新体检并刷新证据卡"}
          </button>
          <div className="proof-links">
            <Link href={`/card/${report.id}`} data-testid="go-card-button"><Lightbulb size={18} />查看求职证据卡</Link>
            <Link href={`/trace/${report.id}`} data-testid="go-trace-button"><Activity size={18} />展开智能体轨迹</Link>
          </div>
        </aside>
      </section>
      <section className="panel recruiter-strip">
        <ShieldCheck size={20} />
        <div>
          <h2>招聘官视角</h2>
          <p>{isGreen ? "新增证明材料让贡献、样本量和结果指标更清楚，简历可以进入投递。" : "招聘官可能会担心：你是否真的做过用户调研，以及活动结果是否可量化。"}</p>
        </div>
        <span className="status-pill neutral">报告编号：{reportId.slice(0, 8)}</span>
      </section>
    </main>
  );
}

function HeaderLite() {
  return (
    <header className="topbar">
      <Link className="brand-lockup link-reset" href="/">
        <div className="brand-mark">体</div>
        <div>
          <h1>投前体检</h1>
          <p>贴岗位，贴简历，30 秒看能不能投</p>
        </div>
      </Link>
      <div className="boundary-note">只判断“可证明性”，不验证经历真实性</div>
    </header>
  );
}
